import 'package:uni_links/uni_links.dart';

class DeepLinkHandler {
  static Future<void> handleDeepLink(Uri uri) async {
    // Parse the deep link and extract the route and parameters
    final route = uri.pathSegments[0];
    final parameters = uri.queryParameters;

    // Navigate to the appropriate route based on the parsed route
    switch (route) {
      case 'profile':
        // Validate the profile ID parameter
        if (!parameters.containsKey('id')) {
          throw Exception('Missing profile ID');
        }

        // Authorize the user for the requested profile
        final profileId = parameters['id'];
        await authorizeProfile(profileId);

        // Navigate to the profile screen with the validated profile ID
        Navigator.pushNamed(context, '/profile', arguments: {'id': profileId});
        break;
      case 'payment':
        // Validate the payment confirmation parameter
        if (!parameters.containsKey('confirm')) {
          throw Exception('Missing payment confirmation');
        }

        // Authorize the user for the requested payment
        final paymentConfirmation = parameters['confirm'];
        await authorizePayment(paymentConfirmation);

        // Navigate to the payment screen with the validated payment confirmation
        Navigator.pushNamed(context, '/payment', arguments: {'confirm': paymentConfirmation});
        break;
      default:
        throw Exception('Invalid deep link route');
    }
  }
}